INSERT INTO conversion_events (id, email, user_id, event_type, event_data, created_at) VALUES ('313bdc40-6c08-45be-837a-ca16804cd76e', NULL, NULL, 'card_drawn', '{"cardName": "神聖陰性", "readingType": "lightworker_single"}', '2026-04-16 05:00:00.066224+00');
INSERT INTO conversion_events (id, email, user_id, event_type, event_data, created_at) VALUES ('ece126dd-4285-44da-869a-ff428e554b5a', 'wadehuang77@gmail.com', NULL, 'email_submitted', '{"card_data": {"id": 9, "name": "神聖陰性", "nameEn": "Divine Feminine", "keywords": ["陰性能量", "接受", "直覺", "創造力"], "soulQuestion": "我在哪些生活領域過度使用陽性能量而忽略了陰性能量？我準備好接受、臣服和信任流動了嗎？", "cosmicMessage": "神聖陰性的能量正在地球上崛起,而你是這個古老力量回歸的管道之一。陰性能量不是關於性別,而是關於接受、流動、直覺、滋養和創造的原則。這是月亮的能量、水的智慧、子宮的創造力。經過數千年的壓抑,神聖陰性正在覺醒,要求被看見、被榮耀和被體現。你內在的女神正在覺醒,邀請你進入更深的自我接納和創造力流動。", "deeperMeaning": "神聖陰性教導我們「存在」的力量,而不只是「行動」。它提醒我們接受與給予同樣重要,休息與工作同樣有價值,感受與思考同樣智慧。陰性能量是循環的、螺旋的、包容的,與陽性能量的線性、目標導向形成互補。在一個過度陽性化的世界中,重新平衡陰性能量是個人和集體療癒的關鍵。這包括榮耀我們的身體、情緒和直覺智慧,學習接受幫助,允許事物有機地展開,與自然週期對齊。神聖陰性也是深刻創造力的源泉,從「無」的空間中誕生「有」。", "energyHealing": "專注於薦骨脈輪和心輪的療癒和平衡,這是陰性能量的中心。使用月光石、玫瑰石英或珍珠來連接神聖陰性。進行子宮療癒冥想,即使你沒有物理子宮,能量子宮仍然存在。使用玫瑰、依蘭或茉莉精油來打開陰性能量。進行柔和流動的瑜伽練習如陰瑜伽。在滿月下進行能量淨化和充能儀式。視覺化粉色或銀色的月光充滿你的整個存在,軟化和打開你。進行聲音療癒,唱誦女神咒語或聆聽子宮鼓的韻律。", "actionGuidance": "建立與月亮週期的連結,追蹤你的能量和情緒如何隨月相變化。給自己許可休息、接受和「無所事事」而不感到愧疚。探索陰性靈性實踐如女神冥想、子宮療癒或神聖舞蹈。滋養你的身體,給它美好的食物、觸碰和關注。創造藝術、音樂或任何形式的創意表達。建立一個女神祭壇,榮耀神聖陰性的不同面向。在水中冥想或沐浴,連接水元素的陰性智慧。練習接受他人的給予和支持。探索你與母親、女性祖先和女性集體的關係。", "currentSituation": "你可能一直在過度使用陽性能量——不斷行動、推動、控制和達成。你可能感到疲憊、枯竭或與自己的身體和情感失去連結。你的陰性面向可能一直在呼喚你的注意——透過身體症狀、情緒波動或對休息和滋養的深度渴望。或者,你可能剛開始探索女神能量、月亮週期或陰性靈性實踐。這張牌鼓勵你更深地榮耀和體現你內在的神聖陰性,無論你的生理性別是什麼。"}, "reading_type": "lightworker_single"}', '2026-04-16 05:00:14.935914+00');
