INSERT INTO conversion_events (id, email, user_id, event_type, event_data, created_at) VALUES ('2b5da665-661b-463d-835c-e780d66648ab', NULL, NULL, 'card_drawn', '{"cardName": "緩慢", "readingType": "osho_single"}', '2026-04-16 05:00:23.942743+00');
INSERT INTO conversion_events (id, email, user_id, event_type, event_data, created_at) VALUES ('995235c1-ab81-407a-a1e6-7c2e218b637d', 'wadehuang77@gmail.com', NULL, 'email_submitted', '{"card_data": {"id": 15, "name": "緩慢", "image": "https://images.pexels.com/photos/1252983/pexels-photo-1252983.jpeg?auto=compress&cs=tinysrgb&w=800", "meanings": {"currentEnergy": "生命在邀請你慢下來。不是因為你懶惰，而是因為你需要深度而非速度。在這個快速的世界中，緩慢是一種抗拒，一種回歸本質的方式。當你慢下來，你才能真正感受、真正看見、真正活著。這個能量提醒你：重要的不是你走得多快，而是你是否真正在走自己的路。緩慢是品味生命的方式，是讓每個時刻變得有意義的秘訣。不要趕路，你不是在逃避，你是在抵達。", "dailyGuidance": "今天，刻意地慢下來。走路時慢一點，說話時慢一點，吃飯時慢一點。注意當你慢下來時發生了什麼：你開始注意到細節，你開始感受到身體，你開始聽見內在的聲音。今天不是完成最多事情的日子，而是深入做好每一件事的日子。品質重於數量。當你感到匆忙的衝動時，停下來，深呼吸。問自己：我在趕什麼？真的有那麼緊急嗎？通常答案是沒有。給自己緩慢的許可。", "meditationEntry": "找一個舒適的地方坐下。現在，將你的呼吸放慢，非常慢。吸氣數到六，吐氣數到六。感受每一個呼吸的細節。然後，緩慢地移動你的手，非常緩慢，好像在水中。感受空氣的質地，感受肌肉的運動。讓一切都慢下來。在這個緩慢中，時間展開了，每個瞬間變得廣闊。你不再被時間追趕，你成為時間本身。在緩慢中，你找到了永恆。", "blockageAnalysis": "你卡住是因為一直在奔跑，卻從未到達。你以為速度會帶你到目的地，但其實它只是讓你錯過沿途的一切。真正的卡點是：你在逃避當下，用忙碌填滿空間，因為害怕面對內在的寧靜。但那份寧靜正是你需要的。當你願意慢下來，真正臨在於每個時刻，你會發現你已經到達了。目的地不在未來，而在當下。慢下來，回家。", "emotionalInsight": "你的焦慮和匆忙感來自於一個信念：你必須不斷奔跑才能值得存在。但這是謊言。你的價值不在於你的生產力，而在於你的存在本身。當你慢下來，你會感到一陣恐慌，因為你被制約相信慢就是懶。但仔細感受，在那恐慌之下，有一份深深的渴望：渴望休息，渴望安靜，渴望只是存在而不用證明什麼。聆聽那個渴望，它來自你最深的智慧。"}, "subtitle": "Slowness"}, "reading_type": "osho_single"}', '2026-04-16 05:00:34.106042+00');
