INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('ce7ed906-8215-4642-905b-802ba0180eaa', 'wadehuang77@gmail.com', 'osho_single', '{"id": 20, "name": "超越幻象", "image": "https://images.pexels.com/photos/1274260/pexels-photo-1274260.jpeg?auto=compress&cs=tinysrgb&w=800", "meanings": {"currentEnergy": "你正在看穿幻象，看見事物本來的樣子。你一直生活在一個由信念、期待、恐懼構成的虛擬世界，現在那個世界的牆正在倒塌。這可能讓人迷失方向，因為你失去了所有的參考點。但這也是最大的禮物：看見真相。你開始明白，你以為重要的很多事其實不重要，你以為真實的很多事其實是幻象。這是覺醒的開始，從夢中醒來，看見生命本來的光輝。", "dailyGuidance": "今天，質疑你的假設。那些你以為是「就是這樣」的事，真的是嗎？你認為你需要某樣東西才能快樂，真的嗎？你相信某個人或情況限制了你，真的嗎？今天，看穿這些故事。它們是真的，還是你相信它們，所以它們看起來是真的？當你開始質疑，幻象就開始瓦解。你會發現，你比你以為的更自由。你的快樂不依賴於外在條件，你的力量從來沒有被奪走。你一直是完整的，只是忘記了。", "meditationEntry": "想像你在看一部電影，非常投入。你與角色一起哭、一起笑、一起恐懼。然後，突然，燈亮了。你看見螢幕，看見座位，你記起：這只是電影。那個釋然的感覺，那個「啊，原來如此」的時刻，就是超越幻象。現在，看看你的生命。你一直以為的那些「真實」，如果只是一部電影呢？不是說它們不重要，而是說它們不是全部。你是那個看電影的人，不是螢幕上的角色。記住這個，一切都改變了。", "blockageAnalysis": "你卡住是因為還在執著於某個幻象。也許是完美的關係、完美的生活、完美的自己。但那個完美不存在，它只是頭腦創造的形象。真正的卡點是：你在追逐一個海市蜃樓，越追越遠。當你願意停下來，看清那是幻象，你會發現真正的美就在這裡，在不完美的現實中。真實的關係、真實的生活、真實的你，比任何幻想都更豐富、更有生命力。停止追逐，開始看見。這就是自由。", "emotionalInsight": "你感到一種奇怪的混合：失落和解放。失落是因為舊的世界觀正在瓦解，那些你抓著的信念不再有效。解放是因為你終於看見，那些信念其實是牢籠。你的情緒正在幫助你穿越這個轉變。允許悲傷，因為你正在哀悼一個幻象。允許喜悅，因為你正在發現真相。這是一個微妙的時刻，你站在兩個世界之間。不要急著重建新的信念，先享受這個開闊的空間。真相不需要被相信，它只需要被看見。"}, "subtitle": "Beyond Illusion"}', '2026-04-02 02:58:01.055888+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('331bfe7c-e36b-4cc3-a067-ff4edd4021a8', 'wadehuang77@gmail.com', 'osho_single', '{"id": 16, "name": "打雷", "image": "https://images.pexels.com/photos/1162251/pexels-photo-1162251.jpeg?auto=compress&cs=tinysrgb&w=800", "meanings": {"currentEnergy": "這是震撼與覺醒的能量。生命正在用一個突如其來的事件喚醒你，打破你的昏睡。這可能是一個危機、一個失落、一個意外，它來得如此迅速，你來不及準備。但這正是它的目的：打破你的防禦機制，讓真相直擊你的核心。打雷是毀滅性的，但也是啟蒙性的。它燒毀舊的結構，清理道路，讓新的光可以照進來。這是一個混亂但必要的時刻，不要試圖理解，只是讓它改變你。", "dailyGuidance": "今天，如果發生讓你震驚或不安的事，不要立刻反應或防衛。停下來，深呼吸。問自己：這個震撼想告訴我什麼？它在打破什麼舊的模式？通常，打雷來臨時，我們會想要立刻恢復控制，修復，回到原狀。但今天，抗拒那個衝動。允許震撼做它的工作。它正在清理你生命中已經死去但還沒有被移除的東西。信任這個毀滅，它是為了創造空間給新的生命。", "meditationEntry": "想像一個晴朗的天空，然後突然，一道閃電劈下。感受那個震撼，那個突然性。一切都被照亮，然後黑暗。但在那個閃光的瞬間，你看見了一切。現在，想像你的生命。那個打雷就是那個讓你看清的時刻。它毀滅了，但也啟蒙了。感受那個能量在你體內，不要抗拒它。讓它燒毀所有虛假的，所有不再服務你的。在灰燼中，新的會升起。你已經被改變了，永遠。", "blockageAnalysis": "你卡住是因為試圖從打雷中恢復到「正常」。但舊的正常已經不存在了，你必須建立新的正常。真正的卡點是：你在抗拒這個根本性的改變，還想抓住碎片重建舊的。但打雷已經說得很清楚：那個不再有效。當你願意完全放手，不試圖拯救任何舊的，你會發現一個全新的可能性展開。打雷清理了道路，現在你可以建立真正屬於你的生活，而不是你以為應該是的生活。", "emotionalInsight": "你感到震驚、無助、甚至憤怒。為什麼是我？為什麼是現在？但打雷不是懲罰，而是覺醒的工具。你一直生活在一個舒適但虛假的結構中，打雷來打破它。是的，這很痛苦，因為你失去了安全感。但仔細看，那份安全感本來就是幻覺。打雷正在強迫你面對真相，面對你一直逃避的東西。你的情緒是正常的，允許自己感受它們。但不要困在其中，這只是過渡。在混亂之後，會有驚人的清晰。"}, "subtitle": "Thunderbolt"}', '2026-04-02 02:58:47.087267+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('e81bd13f-2502-40e2-8a54-4c6c340585c4', 'wadehuang77@gmail.com', 'work_your_light_single', '{"id": 20, "suit": "行動牌", "title": "Get Grounded", "titleChinese": "落地扎根", "interpretation": {"coreMeaning": "這張牌指出你現在需要的是接地——與地球物理連結,讓你的能量下沉並穩定。對於高敏感者、共感者和靈性工作者來說,很容易變得太過「浮在空中」,活在高頻能量和靈性領域中,而與物質現實失去連結。當你沒有好好接地時,你會感到空飄、焦慮、困惑,容易吸收他人的能量,邊界變得模糊。你可能也會在物質生活中遇到困難,例如財務問題、難以完成事務、或感覺與身體斷開連結。接地不會限制你的靈性能力,反而會增強它,因為你需要穩固的根才能安全地向上延伸。", "energyQualities": "這張牌帶來穩定、錨定和物質連結的能量,如同深深紮根的古樹。它的振動頻率低而沉穩,與你的海底輪(根輪)強烈共鳴。這是一種大地的能量,提供安全感、穩定性和歸屬感。它幫助你的能量向下流動,進入身體和地球,而不是飄散在空中。這股能量創造清晰的界限,讓你能辨識什麼是你的能量,什麼不是。它也增強你在物質世界中顯化和採取行動的能力。這是一種保護和淨化的能量,因為大地母親會吸收和轉化不需要的能量。", "higherSelfMessage": "你的高我想要你理解,你是靈性存有正在經歷人類經驗,而不是人類試圖變得靈性。這意味著你的靈性和你的物質性都同等重要。你的身體不是監獄,地球不是懲罰——它們是你選擇來經歷和學習的神聖工具。當你好好接地,你實際上變得更有能力接收和傳遞高頻能量,因為你有穩定的管道和強大的容器。就像避雷針需要深深紮根在地球才能安全地傳導電力一樣,你也需要接地才能安全地傳導宇宙能量。不要害怕或輕視物質世界——學習在天堂和地球之間架起橋樑。", "spiritualGuidance": "每天花時間實際接地。最有效的方法是赤腳站在或走在自然的土地上——草地、沙灘、土壤。這不是象徵性的,而是實際的電子交換,能立即平衡你的能量場。如果無法接觸真正的土地,抱著樹木或觸摸植物也有幫助。想像你有根從腳底延伸深入地球中心,錨定你到大地母親。使用接地的水晶,如黑碧璽、煙水晶或赤鐵礦。進行身體運動,特別是讓你感受到身體重量的活動,如瑜伽、太極或重訓。吃根莖類食物,如馬鈴薯、胡蘿蔔、甜菜根。穿紅色或黑色的衣服。做任何讓你感受到當下和身體的事情。當你感到空飄或焦慮時,立即採取接地行動。", "suitableQuestions": "這張牌適合在你感到空飄、焦慮、失去連結、或難以專注時詢問。當你發現自己容易吸收他人能量、邊界模糊、或在物質生活中掙扎時,這張牌能給予解方。你可以問：「我如何能更好地接地？」「為什麼我感到如此空飄？」「如何在靈性和物質之間取得平衡？」「什麼能幫助我感到更穩定？」「如何保護我的能量場？」這張牌也適合詢問關於能量保護、界限設立、物質顯化,以及如何在保持靈性連結的同時也紮根在地球的問題。"}}', '2026-04-02 03:01:03.452769+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('cb503d42-d752-475a-a33f-a9a1576bd687', 'wadehuang77@gmail.com', 'osho_single', '{"id": 35, "name": "妥協", "image": "https://images.pexels.com/photos/3184611/pexels-photo-3184611.jpeg?auto=compress&cs=tinysrgb&w=800", "meanings": {"currentEnergy": "你現在面對一個選擇：堅持你的立場還是妥協？這張牌不是在說妥協總是對或錯，而是在邀請你檢視：你為什麼要妥協？如果是為了和平、理解、或因為你看見另一個觀點的價值，妥協是智慧。但如果是因為害怕衝突、想取悅、或失去你自己的中心，妥協是背叛。關鍵是：在妥協中，你還保有你的完整性嗎？還是你在出賣自己的真相？", "dailyGuidance": "今天，當你面對需要妥協的情況，慢下來，感受你的身體。真正的妥協在你身體裡感覺是開放的，像「我可以看見另一邊，我願意找中間路」。錯誤的妥協感覺是緊縮的，像「我不想這樣但我別無選擇」。如果是後者，那不是妥協，那是屈服。在那個情況，你需要設立界限，即使不舒服。記住：妥協關於找雙贏，屈服關於你輸。不要混淆這兩者。", "meditationEntry": "想像兩個人在拔河,每個人都用盡全力拉,沒人願意讓步。他們都累了、沮喪了,但都不願放手,因為那感覺像輸。現在,想像其中一個人有一個主意:如果我們放下繩子,一起找一個我們都想去的方向呢?一開始另一個人懷疑,但然後他們嘗試了。他們發現當他們不在對抗,而是在合作,他們可以去很遠的地方。妥協不是弱化你的力量,而是結合它。", "blockageAnalysis": "你卡住是因為在一個非黑即白的思維：要麼我贏要麼你贏。真正的卡點是：你不相信雙贏是可能的。你看關係為一個零和遊戲，所以每個妥協感覺像損失。但大多數情況，有第三個選項，一個你們兩個都沒想到的解決方案，它榮譽雙方的需要。找到它需要創意、溝通、和願意放下「我是對的」的姿態。當你從對錯思維轉到「我們怎麼都得到我們需要的」思維，突破就出現了。", "emotionalInsight": "你可能有一個模式：總是妥協、總是讓步、總是把別人的需要放在你的前面。這來自一個信念：衝突是危險的，取悅別人是安全的。但這個模式讓你累積怨恨和失去自我。或者，你可能有相反的模式：從不妥協、總是堅持己見、看妥協為軟弱。這來自一個信念：讓步是失敗，控制是力量。但這個模式讓你孤立和剛性。真正的智慧是在這兩個極端之間：知道什麼時候彎曲，什麼時候堅定。"}, "subtitle": "Compromise"}', '2026-04-02 03:12:13.366257+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('cf62b367-d71f-4edc-b122-875b22bed81c', 'wadehuang77@gmail.com', 'work_your_light_single', '{"id": 10, "suit": "詢問牌", "title": "Crystal Child", "titleChinese": "水晶小孩", "interpretation": {"coreMeaning": "這張牌認出你是水晶靈魂的一員,你來到地球是為了錨定無條件的愛、療癒和更高的振動頻率。水晶小孩是靛藍戰士之後的和平締造者,你們來延續改革,但以更溫和、更有愛的方式。你的本質極度敏感、直覺強大、天生具有療癒能力。你可能對能量、情緒和他人的痛苦感同身受到不舒服的程度。你的存在本身就是療癒,你不需要做太多,只需要成為你自己,你的高振動能量就會影響周圍的環境和人。", "energyQualities": "這張牌帶來純淨、療癒和高頻的愛的能量,如同清澈的水晶折射彩虹光芒。它的振動頻率非常高且精微,與所有脈輪共鳴,特別是心輪和頂輪。這是一種無條件的愛的能量,能夠療癒深層的創傷並提升振動頻率。它帶來和平、寧靜和神聖的臨在感。這股能量極度敏感和接收,能夠感知最微細的能量變化。它激活你的療癒能力,幫助你成為愛與光的純淨管道。它也帶來保護,提醒你在服務他人的同時也要照顧自己。", "higherSelfMessage": "你的高我想要你知道,你的敏感不是弱點,而是你最大的力量。你能夠感知他人和環境的能量,是因為你來這裡協助療癒和轉化這些能量。你的溫柔、同理心和無條件的愛是這個世界迫切需要的。你可能在成長過程中被告知要「堅強一點」或「不要那麼敏感」,但這些建議是錯誤的。你的敏感正是你的天賦,你的溫柔正是你的力量。你的使命是將基督意識(無條件的愛)錨定到地球,透過你的存在提升集體意識。你是新地球能量的化身,你的純潔和真實正在改變世界。", "spiritualGuidance": "學習保護和管理你的能量場,因為作為水晶小孩,你像海綿一樣吸收周圍的能量。建立強大的每日能量清理和保護練習。花時間在大自然中恢復和充電。學會辨識哪些能量是你的,哪些是他人的。不要試圖拯救所有人,因為這會耗盡你。你的工作是保持你自己的高振動,這本身就是最大的服務。發展你天生的療癒能力,無論是透過能量療癒、藝術、音樂或其他媒介。與水晶、植物和動物連結,它們是你的自然夥伴。記住,你不需要證明什麼或成為別人期望的樣子,只需要真實地做你自己,你的光就會照亮世界。", "suitableQuestions": "這張牌適合在你對自己的極度敏感感到困惑、需要確認你的療癒天賦、或尋求如何管理能量敏感度時詢問。當你感到被世界的痛苦淹沒,或當你知道你來這裡是為了療癒但不確定如何進行時,這張牌能給予指引。你可以問：「我是水晶小孩嗎？」「如何保護我的能量場？」「如何使用我的療癒天賦？」「為什麼我這麼敏感？」「如何在服務他人的同時照顧自己？」這張牌也適合詢問關於能量敏感、療癒工作、以及如何活出你的高振動本質的問題。"}}', '2026-04-02 03:12:57.225373+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('99cf42e3-78e6-49e1-a6eb-c6f47135f2c9', 'wadehuang77@gmail.com', 'dragons_single', '{"cardName": "火山龍爆發", "keywords": ["爆發", "釋放", "重生"], "cardNameEn": "Volcano Dragon Eruption"}', '2026-04-02 03:26:12.286352+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('e8dc4002-6b42-4f9b-a39c-03721925f57a', 'wadehuang77@gmail.com', 'work_your_light_single', '{"id": 13, "suit": "詢問牌", "title": "Starseed", "titleChinese": "星際種子", "interpretation": {"coreMeaning": "這張牌再次確認你的星際本質,並強調你雙重使命的緊迫性。作為星際種子,你同時承擔著提升自身意識和協助地球揚升的神聖使命。你內在感受到的時間緊迫感不是壓力或焦慮,而是靈魂層面的記憶——你知道這個轉化窗口的寶貴和有限。你會一直感到不安,直到你開始活出你的真正召喚。這不是關於做什麼職業或達成什麼成就,而是關於成為你真正是誰,並讓這個真實性照亮世界。找到那個點亮你、讓你充滿熱情的事物,那就是你的指路明燈。", "energyQualities": "這張牌帶來催化和喚醒的能量,如同內在的鬧鐘響起,呼喚你起床並記起你是誰。它的振動頻率高而緊急,與你的所有脈輪共鳴,特別是靈魂星脈輪。這是一種激活和加速的能量,推動你離開舒適區,踏入你的真正力量。它帶來清晰的目的感和方向感,消除拖延和恐懼。這股能量連結你與你的星際家族和更高使命,給予你勇氣和動力去做你來此要做的事。它也帶來一種健康的緊迫感,不是焦慮,而是專注和承諾。", "higherSelfMessage": "你的高我想要你記起,你來到地球不是為了過一個平凡的人生。你是自願者,是先鋒,是光的戰士。在你出生之前,你就知道這個星球正處於關鍵的轉化期,而你選擇來這裡協助這個過程。那種內在的不安、那種「必須做些什麼」的感覺,正是你的靈魂在催促你記起你的使命並開始行動。你的任務不是拯救世界,而是活出你的最高振動,成為你來此要成為的光。當你這樣做時,你會自動影響周圍的能量場,激勵他人也想起他們自己。時間確實寶貴,但不是讓你焦慮,而是讓你聚焦。", "spiritualGuidance": "停止尋找完美的路徑或等待完美的時機。開始問自己：「什麼讓我的心歌唱？什麼讓我感到活著？」然後開始朝那個方向移動,即使只是小步。你的熱情是你的GPS,它會引導你到你需要去的地方。不要試圖弄清楚整個計畫,只需要看見下一步並踏出去。連結其他星際種子,你們會互相認出彼此,互相支持和激勵。記住,你的使命可能不是宏大的或世界矚目的,它可能是簡單而深刻的——養育孩子、創作藝術、療癒他人、或只是在你的社區中成為光的存在。重要的是真實性和振動頻率,而非外在形式。", "suitableQuestions": "這張牌適合在你感到內在不安、知道自己需要做些什麼卻不確定是什麼時詢問。當你感到時間緊迫或生命正在召喚你踏入更大的事物時,這張牌能給予清晰。你可以問：「我的靈魂使命是什麼？」「什麼真正點亮我的心？」「我如何能開始活出我的召喚？」「我來地球的目的是什麼？」「下一步是什麼？」這張牌也適合詢問關於人生目的、靈魂使命、熱情追尋,以及如何從知道轉為行動的問題。"}}', '2026-04-02 03:27:31.594751+00');
