INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('21f6f144-ecc4-4099-9336-f8f9612b5222', 'wadehuang77@gmail.com', 'egyptian_gods_single', '{"cardName": "Bes - Dwarf God", "cardNameChinese": "貝斯 - 侏儒神"}', '2026-04-02 04:31:09.500205+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('39ce3256-8d25-4d1b-ac36-a5b7adaee264', 'wadehuang77@gmail.com', 'work_your_light_single', '{"id": 17, "suit": "行動牌", "title": "Break the Chain", "titleChinese": "打破鎖鏈", "interpretation": {"coreMeaning": "這張牌揭示你正背負著不屬於你的世代創傷和家族模式。你的焦慮、恐懼、限制性信念或行為模式,可能不是源於你自己的經驗,而是從祖先那裡繼承下來的未療癒創傷。你來到這裡不僅是為了活你自己的人生,也是為了成為家族療癒者,打破那些代代相傳的痛苦鎖鏈。當你療癒自己,你也在療癒你的祖先和未來的世代。這是深刻而神聖的工作,需要勇氣去面對不是你造成的痛苦,但你有能力轉化它。", "energyQualities": "這張牌帶來解放和切斷的能量,如同鋒利的神聖之劍切斷束縛的鎖鏈。它的振動頻率深沉而轉化,觸及細胞記憶和DNA層面的療癒。這是一種世代療癒的能量,能夠穿越時間和空間,影響過去和未來。它連結你與你的祖先,同時賦予你與他們的痛苦模式分離的力量。這股能量帶來深刻的釋放感,如同卸下了多年的重擔。它也喚醒你作為家族療癒者的角色和力量,讓你成為打破循環的那一個。", "higherSelfMessage": "你的高我想要你知道,你選擇出生在這個家族不是意外或懲罰。你的靈魂選擇這個血脈,因為它知道你有力量和勇氣來打破世代循環,為你的家族帶來療癒和解放。你可能一直感到某些模式或情緒不是真正屬於你的——那種莫名的恐懼、那種根深蒂固的限制性信念、那種無法解釋的悲傷。這些可能是你的祖母、曾祖母,或更久遠祖先的未竟之事。現在,透過你的意識和療癒工作,這些鎖鏈可以被打破。你不僅在為自己創造自由,也在為整個血脈創造自由。", "spiritualGuidance": "開始探索你的家族歷史和模式。與家人交談,了解他們的故事、創傷和未實現的夢想。注意你身上重複出現的模式是否也在你的父母或祖父母身上出現。識別你想要打破的特定模式——可能是關於金錢、關係、成功、表達或價值的信念。進行家族系統排列、祖先療癒儀式,或與專業的世代創傷治療師工作。創建一個祖先祭壇,向你的祖先表達感謝,同時清晰地聲明你正在釋放不再服務你的模式。原諒你的祖先——他們也是在他們有限的意識和資源下盡力而為。宣告:「這鎖鏈在我這裡結束。我選擇不同的道路。」然後活出這個選擇。", "suitableQuestions": "這張牌適合在你注意到重複的家族模式、感到被不屬於你的情緒或信念困擾、或想要為你的家族帶來療癒時詢問。當你準備好做深層的世代療癒工作時,這張牌能給予指引。你可以問：「我從家族繼承了什麼模式？」「如何打破這些世代鎖鏈？」「我需要療癒什麼祖先創傷？」「如何成為我家族的療癒者？」「什麼不屬於我但我一直在背負？」這張牌也適合詢問關於家族療癒、世代創傷釋放、祖先工作,以及如何為未來世代創造不同遺產的問題。"}}', '2026-04-02 04:31:26.124474+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('ddfed5b4-3479-4582-9650-66c2e49e1943', 'wadehuang77@gmail.com', 'lightworker_single', '{"cardName": "光之使者"}', '2026-04-02 04:31:45.307783+00');
