INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('701a9726-f386-4450-9743-38d6c0c68346', 'wadehuang77@gmail.com', 'lightworker_single', '{"id": 9, "name": "神聖陰性", "nameEn": "Divine Feminine", "keywords": ["陰性能量", "接受", "直覺", "創造力"], "soulQuestion": "我在哪些生活領域過度使用陽性能量而忽略了陰性能量？我準備好接受、臣服和信任流動了嗎？", "cosmicMessage": "神聖陰性的能量正在地球上崛起,而你是這個古老力量回歸的管道之一。陰性能量不是關於性別,而是關於接受、流動、直覺、滋養和創造的原則。這是月亮的能量、水的智慧、子宮的創造力。經過數千年的壓抑,神聖陰性正在覺醒,要求被看見、被榮耀和被體現。你內在的女神正在覺醒,邀請你進入更深的自我接納和創造力流動。", "deeperMeaning": "神聖陰性教導我們「存在」的力量,而不只是「行動」。它提醒我們接受與給予同樣重要,休息與工作同樣有價值,感受與思考同樣智慧。陰性能量是循環的、螺旋的、包容的,與陽性能量的線性、目標導向形成互補。在一個過度陽性化的世界中,重新平衡陰性能量是個人和集體療癒的關鍵。這包括榮耀我們的身體、情緒和直覺智慧,學習接受幫助,允許事物有機地展開,與自然週期對齊。神聖陰性也是深刻創造力的源泉,從「無」的空間中誕生「有」。", "energyHealing": "專注於薦骨脈輪和心輪的療癒和平衡,這是陰性能量的中心。使用月光石、玫瑰石英或珍珠來連接神聖陰性。進行子宮療癒冥想,即使你沒有物理子宮,能量子宮仍然存在。使用玫瑰、依蘭或茉莉精油來打開陰性能量。進行柔和流動的瑜伽練習如陰瑜伽。在滿月下進行能量淨化和充能儀式。視覺化粉色或銀色的月光充滿你的整個存在,軟化和打開你。進行聲音療癒,唱誦女神咒語或聆聽子宮鼓的韻律。", "actionGuidance": "建立與月亮週期的連結,追蹤你的能量和情緒如何隨月相變化。給自己許可休息、接受和「無所事事」而不感到愧疚。探索陰性靈性實踐如女神冥想、子宮療癒或神聖舞蹈。滋養你的身體,給它美好的食物、觸碰和關注。創造藝術、音樂或任何形式的創意表達。建立一個女神祭壇,榮耀神聖陰性的不同面向。在水中冥想或沐浴,連接水元素的陰性智慧。練習接受他人的給予和支持。探索你與母親、女性祖先和女性集體的關係。", "currentSituation": "你可能一直在過度使用陽性能量——不斷行動、推動、控制和達成。你可能感到疲憊、枯竭或與自己的身體和情感失去連結。你的陰性面向可能一直在呼喚你的注意——透過身體症狀、情緒波動或對休息和滋養的深度渴望。或者,你可能剛開始探索女神能量、月亮週期或陰性靈性實踐。這張牌鼓勵你更深地榮耀和體現你內在的神聖陰性,無論你的生理性別是什麼。"}', '2026-04-16 05:00:14.816272+00');
INSERT INTO reading_unlocks (id, email, reading_type, card_data, unlocked_at) VALUES ('865d9f63-019c-41ba-9c88-f20901e0c247', 'wadehuang77@gmail.com', 'osho_single', '{"id": 15, "name": "緩慢", "image": "https://images.pexels.com/photos/1252983/pexels-photo-1252983.jpeg?auto=compress&cs=tinysrgb&w=800", "meanings": {"currentEnergy": "生命在邀請你慢下來。不是因為你懶惰，而是因為你需要深度而非速度。在這個快速的世界中，緩慢是一種抗拒，一種回歸本質的方式。當你慢下來，你才能真正感受、真正看見、真正活著。這個能量提醒你：重要的不是你走得多快，而是你是否真正在走自己的路。緩慢是品味生命的方式，是讓每個時刻變得有意義的秘訣。不要趕路，你不是在逃避，你是在抵達。", "dailyGuidance": "今天，刻意地慢下來。走路時慢一點，說話時慢一點，吃飯時慢一點。注意當你慢下來時發生了什麼：你開始注意到細節，你開始感受到身體，你開始聽見內在的聲音。今天不是完成最多事情的日子，而是深入做好每一件事的日子。品質重於數量。當你感到匆忙的衝動時，停下來，深呼吸。問自己：我在趕什麼？真的有那麼緊急嗎？通常答案是沒有。給自己緩慢的許可。", "meditationEntry": "找一個舒適的地方坐下。現在，將你的呼吸放慢，非常慢。吸氣數到六，吐氣數到六。感受每一個呼吸的細節。然後，緩慢地移動你的手，非常緩慢，好像在水中。感受空氣的質地，感受肌肉的運動。讓一切都慢下來。在這個緩慢中，時間展開了，每個瞬間變得廣闊。你不再被時間追趕，你成為時間本身。在緩慢中，你找到了永恆。", "blockageAnalysis": "你卡住是因為一直在奔跑，卻從未到達。你以為速度會帶你到目的地，但其實它只是讓你錯過沿途的一切。真正的卡點是：你在逃避當下，用忙碌填滿空間，因為害怕面對內在的寧靜。但那份寧靜正是你需要的。當你願意慢下來，真正臨在於每個時刻，你會發現你已經到達了。目的地不在未來，而在當下。慢下來，回家。", "emotionalInsight": "你的焦慮和匆忙感來自於一個信念：你必須不斷奔跑才能值得存在。但這是謊言。你的價值不在於你的生產力，而在於你的存在本身。當你慢下來，你會感到一陣恐慌，因為你被制約相信慢就是懶。但仔細感受，在那恐慌之下，有一份深深的渴望：渴望休息，渴望安靜，渴望只是存在而不用證明什麼。聆聽那個渴望，它來自你最深的智慧。"}, "subtitle": "Slowness"}', '2026-04-16 05:00:33.980633+00');
